class ExportStrategyRegistry:
    """Pluggable export formats. Only CSV exists today, but this keeps us flexible."""
    def __init__(self):
        self._strategies = {}
    def register(self, fmt, strategy_cls, **default_opts):
        self._strategies[fmt] = (strategy_cls, default_opts)
    def export(self, fmt="csv", **overrides):
        cls, opts = self._strategies[fmt]
        return cls(**{**opts, **overrides}).run()
